#include<bits/stdc++.h>
using namespace std;
int main(){
	string a;
	cin>>a;
	int s[10000]={0},maxs=0,mins=100000,sum=0;
	for(int i=0;i<a.size();i++){
		s[a[i]]+=1;
	}
	for(int i='a';i<='z';i++){
		if(s[i]!=0){
			maxs=max(maxs,s[i]);
			mins=min(mins,s[i]); 
		}
		
	}
	sum=maxs-mins;
	for(int i=2;i<sum;i++){
		if(sum%i==0){
			cout<<"No Answer"<<endl<<0;
			return 0;
		}
	}
	if(sum!=0&&sum!=1){
		cout<<"Lucky Word"<<endl<<sum;
	}else{
		cout<<"No Answer"<<endl<<0;
	}
	
	return 0;
}
